        Set<String> set = new HashSet<>();
        set.add("element1");
        set.add("element2");
        // 遍历
        for (String s : set) {
            System.out.println(s);
        }
        // 检查存在
        if (set.contains("element1")) {
            // 操作
        }
        // 删除
        set.remove("element1");
